from itertools import combinations
class Solution:
    def maximumRequests(self, n, requests):
        m = len(requests)
        for size in range(m, -1, -1):
            for combo in combinations(range(m), size):
                net = [0] * n
                for i in combo:
                    frm, to = requests[i]
                    net[frm] -= 1
                    net[to] += 1
                if all(v == 0 for v in net):
                    return size
        return 0

