class Solution:
    def maximumRequests(self, n, requests):
        m = len(requests)
        best = 0
        for mask in range(1 << m):
            cnt = bin(mask).count('1')
            if cnt <= best:
                continue
            net = [0] * n
            for i in range(m):
                if mask & (1 << i):
                    frm, to = requests[i]
                    net[frm] -= 1
                    net[to] += 1
            if all(v == 0 for v in net):
                best = cnt
        return best

