var maximumRequests = function(n, requests) {
    const m = requests.length;
    let best = 0;
    for (let mask = 0; mask < (1 << m); mask++) {
        let cnt = 0;
        for (let b = 0; b < m; b++) if (mask & (1 << b)) cnt++;
        if (cnt <= best) continue;
        const net = new Array(n).fill(0);
        for (let i = 0; i < m; i++) {
            if (mask & (1 << i)) {
                const frm = requests[i][0], to = requests[i][1];
                net[frm] -= 1;
                net[to] += 1;
            }
        }
        if (net.every(v => v === 0)) best = cnt;
    }
    return best;
};
